import React from 'react';

export default function EmptyState({
  title = "No search results",
  description = "We couldn't find what you were looking for. Please refine your query and try again.",
  primaryAction,
  secondaryAction
}) {
  return (
    <div className="w-full max-w-md mx-auto py-10 px-6 border border-gray-150 rounded-2xl bg-white shadow-xs text-center font-sans">
      {/* SVG Placeholder */}
      <div className="flex items-center justify-center w-12 h-12 rounded-xl bg-purple-50 text-purple-600 mx-auto mb-5 border border-purple-100">
        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
          <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
        </svg>
      </div>

      <h3 className="font-bold text-gray-800 text-lg">{title}</h3>
      <p className="text-gray-400 text-sm mt-2 leading-relaxed px-2">{description}</p>

      {/* Buttons */}
      <div className="flex flex-col sm:flex-row gap-3 items-center justify-center mt-6">
        {primaryAction && (
          <button
            onClick={primaryAction.onClick}
            className="w-full sm:w-auto px-5 py-2.5 bg-purple-600 hover:bg-purple-700 text-white rounded-xl font-semibold text-sm transition"
          >
            {primaryAction.label}
          </button>
        )}
        {secondaryAction && (
          <button
            onClick={secondaryAction.onClick}
            className="w-full sm:w-auto px-5 py-2.5 bg-white hover:bg-gray-50 text-gray-700 border border-gray-300 rounded-xl font-semibold text-sm transition"
          >
            {secondaryAction.label}
          </button>
        )}
      </div>
    </div>
  );
}
